diff --git a/src/MediatR/NotificationPublishers/TaskWhenAllPublisher.cs b/src/MediatR/NotificationPublishers/TaskWhenAllPublisher.cs
index 4b948eb..8c1389a 100644
--- a/src/MediatR/NotificationPublishers/TaskWhenAllPublisher.cs
+++ b/src/MediatR/NotificationPublishers/TaskWhenAllPublisher.cs
@@ -17,12 +17,29 @@ namespace MediatR.NotificationPublishers;
 /// </summary>
 public class TaskWhenAllPublisher : INotificationPublisher
 {
-    public Task Publish(IEnumerable<NotificationHandlerExecutor> handlerExecutors, INotification notification, CancellationToken cancellationToken)
+    public async Task Publish(IEnumerable<NotificationHandlerExecutor> handlerExecutors, INotification notification, CancellationToken cancellationToken)
     {
         var tasks = handlerExecutors
             .Select(handler => handler.HandlerCallback(notification, cancellationToken))
             .ToArray();

-        return Task.WhenAll(tasks);
+        try
+        {
+            await Task.WhenAll(tasks).ConfigureAwait(false);
+        }
+        catch
+        {
+            var innerExceptions = tasks
+                .Where(static t => t.IsFaulted && t.Exception != null)
+                .SelectMany(static t => t.Exception!.Flatten().InnerExceptions)
+                .ToList();
+
+            if (innerExceptions.Count > 0)
+            {
+                throw new AggregateException(innerExceptions);
+            }
+
+            throw;
+        }
     }
 }
